import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import { useListOrganizations } from "@better-auth-ui/solid"
import { PlusCircle } from "lucide-solid"
import { createSignal, For, Show } from "solid-js"
import { Button } from "@/components/ui/button"
import { CreateOrganizationDialog } from "./create-organization-dialog"
import { OrganizationRow } from "./organization-row"

export type OrganizationsProps = {
  authClient: OrganizationAuthClient
}

export function Organizations(props: OrganizationsProps) {
  const organizations = useListOrganizations(props.authClient)
  const [createOpen, setCreateOpen] = createSignal(false)

  return (
    <div class="flex flex-col gap-4">
      <div class="flex items-center justify-between gap-3">
        <div>
          <h3 class="font-medium">Organizations</h3>
          <p class="text-sm text-muted-foreground">
            Create and manage organizations for shared access.
          </p>
        </div>
        <Button onClick={() => setCreateOpen(true)} type="button">
          <PlusCircle class="size-4" />
          Create organization
        </Button>
      </div>

      <Show
        when={!organizations.isPending}
        fallback={
          <p class="text-sm text-muted-foreground">Loading organizations…</p>
        }
      >
        <div class="flex flex-col gap-2">
          <For
            each={organizations.data ?? []}
            fallback={
              <button
                class="rounded-md border border-dashed p-4 text-left text-sm text-muted-foreground transition-colors hover:bg-accent hover:text-accent-foreground"
                onClick={() => setCreateOpen(true)}
                type="button"
              >
                No organizations yet. Create one to enable organization routes.
              </button>
            }
          >
            {(organization) => (
              <OrganizationRow
                authClient={props.authClient}
                organization={organization}
              />
            )}
          </For>
        </div>
      </Show>

      <CreateOrganizationDialog
        open={createOpen()}
        onOpenChange={setCreateOpen}
      />
    </div>
  )
}

import { organizationLocalization } from "@better-auth-ui/core/plugins"
import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import { useAuth, useListUserInvitations } from "@better-auth-ui/solid"
import { For, Show } from "solid-js"
import { Card, CardContent } from "@/components/ui/card"
import { cn } from "@/lib/utils"
import { UserInvitationRow } from "./user-invitation-row"
import { UserInvitationRowSkeleton } from "./user-invitation-row-skeleton"
import { UserInvitationsEmpty } from "./user-invitations-empty"

export type UserInvitationsProps = {
  class?: string
}

type UserInvitation = {
  createdAt?: Date | string | null
  id: string
  organizationName?: string | null
  role?: string | null
}

export function UserInvitations(props: UserInvitationsProps) {
  const auth = useAuth()
  const invitations = useListUserInvitations(
    auth.authClient as OrganizationAuthClient
  )
  const invitationRows = () => (invitations.data ?? []) as UserInvitation[]

  return (
    <div class={cn("flex flex-col gap-3", props.class)}>
      <h2 class="truncate font-semibold text-sm">
        {organizationLocalization.invitations}
      </h2>
      <Card class="p-0">
        <CardContent class="p-0">
          <Show
            when={!invitations.isPending}
            fallback={
              <div class="p-4">
                <UserInvitationRowSkeleton />
              </div>
            }
          >
            <Show
              when={invitationRows().length > 0}
              fallback={<UserInvitationsEmpty />}
            >
              <div class="divide-y">
                <For each={invitationRows()}>
                  {(invitation) => (
                    <div class="p-4">
                      <UserInvitationRow invitation={invitation} />
                    </div>
                  )}
                </For>
              </div>
            </Show>
          </Show>
        </CardContent>
      </Card>
    </div>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins"
import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import {
  useAcceptInvitation,
  useAuth,
  useRejectInvitation
} from "@better-auth-ui/solid"
import { Check, Clock, X } from "lucide-solid"
import { Button } from "@/components/ui/button"
import { organizationPlugin } from "@/lib/auth/organization-plugin"

type RoleMap = Record<string, string>

type UserInvitation = {
  createdAt?: Date | string | null
  id: string
  organizationName?: string | null
  role?: string | null
}

export type UserInvitationRowProps = {
  invitation: UserInvitation
}

const fallbackRoles: RoleMap = {
  owner: "Owner",
  admin: "Admin",
  member: "Member"
}

const fallbackLocalization = {
  accept: "Accept",
  rejectInvitation: "Reject invitation"
} satisfies Pick<OrganizationLocalization, "accept" | "rejectInvitation">

function formatInvitationDate(createdAt?: Date | string | null) {
  if (!createdAt) return "—"

  const date = createdAt instanceof Date ? createdAt : new Date(createdAt)

  if (Number.isNaN(date.getTime())) return "—"

  return date.toLocaleString(undefined, {
    dateStyle: "medium",
    timeStyle: "short"
  })
}

export function UserInvitationRow(props: UserInvitationRowProps) {
  const auth = useAuth()
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | {
          localization?: Pick<
            OrganizationLocalization,
            "accept" | "rejectInvitation"
          >
          roles?: RoleMap
        }
      | undefined
  const organizationLocalization = () =>
    organizationPluginConfig()?.localization ?? fallbackLocalization
  const roles = () => organizationPluginConfig()?.roles ?? fallbackRoles
  const acceptInvitation = useAcceptInvitation(
    auth.authClient as OrganizationAuthClient
  )
  const rejectInvitation = useRejectInvitation(
    auth.authClient as OrganizationAuthClient
  )
  const isPending = () =>
    acceptInvitation.isPending || rejectInvitation.isPending
  const roleLabel = () =>
    roles()[props.invitation.role ?? ""] ?? props.invitation.role ?? "Member"

  return (
    <div class="flex items-center gap-3">
      <div class="flex size-10 shrink-0 items-center justify-center rounded-md bg-muted">
        <Clock class="size-4" />
      </div>
      <div class="flex min-w-0 flex-col">
        <div class="flex items-center gap-1.5">
          <span class="truncate font-medium text-sm leading-tight">
            {props.invitation.organizationName ?? "Organization"}
          </span>
          <span class="rounded-md bg-muted px-2 py-1 font-medium text-muted-foreground text-xs">
            {roleLabel()}
          </span>
        </div>
        <span class="truncate text-muted-foreground text-xs">
          {formatInvitationDate(props.invitation.createdAt)}
        </span>
      </div>
      <div class="ml-auto flex shrink-0 items-center gap-2">
        <Button
          disabled={isPending()}
          onClick={() =>
            acceptInvitation.mutate({ invitationId: props.invitation.id })
          }
          size="sm"
          type="button"
          variant="outline"
        >
          <Check class="size-4" />
          {organizationLocalization().accept}
        </Button>
        <Button
          aria-label={organizationLocalization().rejectInvitation}
          class="text-destructive"
          disabled={isPending()}
          onClick={() =>
            rejectInvitation.mutate({ invitationId: props.invitation.id })
          }
          size="icon-sm"
          type="button"
          variant="outline"
        >
          <X class="size-4" />
        </Button>
      </div>
    </div>
  )
}

import { Skeleton } from "@/components/ui/skeleton"

export function UserInvitationRowSkeleton() {
  return (
    <div class="flex items-center gap-3">
      <Skeleton class="size-10 shrink-0 rounded-md" />
      <div class="flex flex-col gap-1">
        <Skeleton class="h-4 w-40 rounded-md" />
        <Skeleton class="h-3 w-28 rounded-md" />
